1	type Item = { type: string; material: string; enchantment: number; cursed: boolean };
2	type Step = { op: string; items: Item[] };
3	type Result = { premium: number };
4	type ScenarioInput = { customer: { yearsWithMHPCO: number }; steps: Step[] };
5	type ScenarioOutput = { results: Result[] };
6	
7	const COMPONENT_BASE_PREMIUM = 25;
8	const COMPONENT_BUNDLE_PREMIUM = 60;
9	const COMPONENT_BUNDLE_SIZE = 3;
10	const COMPONENT_TYPES = ["rune", "moonstone"];
11	const SAVINGS_PER_BUNDLE =
12	  COMPONENT_BUNDLE_SIZE * COMPONENT_BASE_PREMIUM - COMPONENT_BUNDLE_PREMIUM;
13	
14	const BASE_PREMIUMS: Record<string, number> = {
15	  sword: 100,
16	  amulet: 60,
17	  staff: 80,
18	  potion: 40,
19	  rune: COMPONENT_BASE_PREMIUM,
20	  moonstone: COMPONENT_BASE_PREMIUM,
21	};
22	
23	const FIRST_INSURANCE_SURCHARGE_PERCENT = 10;
24	const CURSED_SURCHARGE_PERCENT = 50;
25	const HIGH_ENCHANTMENT_SURCHARGE_PERCENT = 30;
26	const HIGH_ENCHANTMENT_THRESHOLD = 5;
27	const LOYALTY_DISCOUNT_PERCENT = 20;
28	const LOYALTY_THRESHOLD_YEARS = 2;
29	const REPEAT_CONTRACT_DISCOUNT_PERCENT = 15;
30	const PROCESSING_FEE = 5;
31	
32	const addSurchargePercent = (amount: number, percent: number): number =>
33	  (amount * (100 + percent)) / 100;
34	
35	const applyDiscountPercent = (amount: number, percent: number): number =>
36	  (amount * (100 - percent)) / 100;
37	
38	const addSurchargeIf = (amount: number, condition: boolean, percent: number): number =>
39	  condition ? addSurchargePercent(amount, percent) : amount;
40	
41	const applyDiscountIf = (amount: number, condition: boolean, percent: number): number =>
42	  condition ? applyDiscountPercent(amount, percent) : amount;
43	
44	const itemPremium = (item: Item): number => {
45	  const base = BASE_PREMIUMS[item.type];
46	  const withCursed = addSurchargeIf(base, item.cursed, CURSED_SURCHARGE_PERCENT);
47	  return addSurchargeIf(
48	    withCursed,
49	    item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD,
50	    HIGH_ENCHANTMENT_SURCHARGE_PERCENT,
51	  );
52	};
53	
54	const sumItemPremiums = (items: Item[]): number =>
55	  items.reduce((sum, item) => sum + itemPremium(item), 0);
56	
57	const countItemsOfType = (items: Item[], type: string): number =>
58	  items.filter((item) => item.type === type).length;
59	
60	const bundlesOfType = (items: Item[], type: string): number =>
61	  Math.floor(countItemsOfType(items, type) / COMPONENT_BUNDLE_SIZE);
62	
63	const componentBundleDiscount = (items: Item[]): number =>
64	  COMPONENT_TYPES.reduce(
65	    (savings, type) => savings + bundlesOfType(items, type) * SAVINGS_PER_BUNDLE,
66	    0,
67	  );
68	
69	const quotePremium = (items: Item[], yearsWithMHPCO: number, isFirstQuote: boolean): number => {
70	  const itemsTotal = sumItemPremiums(items) - componentBundleDiscount(items);
71	  const withContractAdjustment = isFirstQuote
72	    ? addSurchargePercent(itemsTotal, FIRST_INSURANCE_SURCHARGE_PERCENT)
73	    : applyDiscountPercent(itemsTotal, REPEAT_CONTRACT_DISCOUNT_PERCENT);
74	  const withLoyalty = applyDiscountIf(
75	    withContractAdjustment,
76	    yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS,
77	    LOYALTY_DISCOUNT_PERCENT,
78	  );
79	  return withLoyalty + PROCESSING_FEE;
80	};
81	
82	export const runScenario = (input: ScenarioInput): ScenarioOutput => ({
83	  results: input.steps.map((step, index) => ({
84	    premium: quotePremium(step.items, input.customer.yearsWithMHPCO, index === 0),
85	  })),
86	});
